import{_ as t,o as a,c as n,ae as i}from"./chunks/framework.BuvKvcPh.js";const r="/Furniture-Designer/images/manufacturing-en.png",m=JSON.parse('{"title":"Manufacturing & Packing","description":"","frontmatter":{},"headers":[],"relativePath":"manufacturing.md","filePath":"manufacturing.md"}'),s={name:"manufacturing.md"};function o(l,e,u,c,g,p){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="manufacturing-packing" tabindex="-1">Manufacturing &amp; Packing <a class="header-anchor" href="#manufacturing-packing" aria-label="Permalink to &quot;Manufacturing &amp; Packing&quot;">​</a></h1><p>Once your 3D design is complete, you must transform abstract geometry into actionable shop instructions.</p><p><img src="'+r+'" alt="Manufacturing Interface"></p><h2 id="the-cut-list" tabindex="-1">The Cut List <a class="header-anchor" href="#the-cut-list" aria-label="Permalink to &quot;The Cut List&quot;">​</a></h2><p>The <strong>Cut List</strong> computes a flat list of every individual wooden plank required to assemble the furniture.</p><ul><li><strong>Thickness Deductions</strong>: The algorithm inherently handles intersections (e.g., shelving naturally terminates against side uprights). Dimensions listed here are exact.</li><li><strong>Grouping</strong>: Identical boards are grouped by quantity.</li><li><strong>Area Calculation</strong>: See exactly how many square meters of raw material the design consumes to help predict supply costs.</li><li><strong>Total Dowel Estimation</strong>: Predicts the exact count of wooden dowels required for the whole structural assembly.</li><li><strong>Exporting</strong>: You can export this view into a highly readable PDF Plan designed to be printed and kept with you in the workshop.</li></ul><h2 id="panel-cut-plan-optimizer" tabindex="-1">Panel Cut Plan Optimizer <a class="header-anchor" href="#panel-cut-plan-optimizer" aria-label="Permalink to &quot;Panel Cut Plan Optimizer&quot;">​</a></h2><p>Instead of trying to manually figure out how to cut your 12 boards out of standard commercial 4x8 MDF sheets, the <strong>Cut Plan Packer</strong> acts as a 2D Bin Packing solver.</p><h3 id="optimizer-features" tabindex="-1">Optimizer Features <a class="header-anchor" href="#optimizer-features" aria-label="Permalink to &quot;Optimizer Features&quot;">​</a></h3><ul><li><strong>Blade Kerf (Saw Thickness)</strong>: Input the thickness of your circular saw blade (e.g., 3mm). The packer respects this margin between every single piece!</li><li><strong>Multiple Panel Stocks</strong>: Buying smaller sheets might sometimes be cheaper than buying large ones. You can input multiple standard sizes available at your local hardware store (e.g., a 2440x1220 sheet for 45€ and a 1220x600 sheet for 15€).</li><li><strong>Smart Mix Algorithm</strong>: The engine computes combinations of panels and returns the absolute cheapest buying option using combinations of different panels, returning a total cart cost.</li><li><strong>Orientation Awareness</strong>: The engine attempts smart rotations to maximize fitting density.</li></ul><p><em>Note: Any pieces that physically cannot fit inside the largest provided panel bounds will be safely excluded and reported in a warning.</em></p>',11)])])}const d=t(s,[["render",o]]);export{m as __pageData,d as default};
